};

import { getUser, getUserPosts } from "@/app/shared/seed";
import { link } from "@/app/shared/links";

export const UserDetailPage = ({
  params,
}: {
  params: { id: string };
}) => {
  const user = getUser(params.id);
  if (!user) {
    return <div>User not found</div>;
  }

  const posts = getUserPosts(params.id);

  return (
    <div>
      <h1>{user.name}</h1>
      <h2>Posts</h2>
      <ul>
        {posts.map((post) => (
          <li key={post.id}>
            <a href={link("/users/:id/posts/:postId", { id: params.id, postId: post.id })}>
              {post.title}
            </a>
          </li>
        ))}
      </ul>
    </div>
  );
};

import { getUser, getPost } from "@/app/shared/seed";
import { link } from "@/app/shared/links";

export const PostDetailPage = ({
  params,
}: {
  params: { id: string; postId: string };
}) => {
  const user = getUser(params.id);
  const post = getPost(params.id, params.postId);
  if (!user || !post) {
    return <div>Post not found</div>;
  }

  return (
    <div>
      <h1>{post.title}</h1>
      <p>User ID: {params.id}</p>
      <p>Post ID: {params.postId}</p>
      <a href={link("/users/:id", { id: params.id })}>Back to {user.name}</a>
    </div>
  );
};

